import React, { useEffect, useState } from "react";
import Navbar from "../components/Navbar";
import { api } from "../lib/api";
import { toast } from "sonner";
import { Trash2, Plus, X } from "lucide-react";

export default function AdminDashboard() {
  const [tab, setTab] = useState("projects");
  const [projects, setProjects] = useState([]);
  const [users, setUsers] = useState([]);
  const [contacts, setContacts] = useState([]);
  const [announcements, setAnnouncements] = useState([]);
  const [showAnn, setShowAnn] = useState(false);
  const [annForm, setAnnForm] = useState({ title: "", body: "" });

  const load = async () => {
    try {
      const [p, u, c, a] = await Promise.all([
        api.get("/projects"),
        api.get("/admin/users"),
        api.get("/admin/contacts"),
        api.get("/announcements"),
      ]);
      setProjects(p.data); setUsers(u.data); setContacts(c.data); setAnnouncements(a.data);
    } catch (e) { toast.error("failed to load admin data"); }
  };

  useEffect(() => { load(); }, []);

  const delProject = async (id) => {
    if (!confirm("delete project?")) return;
    try { await api.delete(`/projects/${id}`); toast.success("deleted"); load(); }
    catch { toast.error("failed"); }
  };

  const delAnn = async (id) => {
    try { await api.delete(`/announcements/${id}`); toast.success("removed"); load(); }
    catch { toast.error("failed"); }
  };

  const addAnn = async (e) => {
    e.preventDefault();
    try {
      await api.post("/announcements", annForm);
      toast.success("announcement posted");
      setAnnForm({ title: "", body: "" });
      setShowAnn(false);
      load();
    } catch (e) { toast.error("failed to post"); }
  };

  const TABS = [
    { k: "projects", label: `projects (${projects.length})` },
    { k: "members", label: `members (${users.length})` },
    { k: "contacts", label: `contacts (${contacts.length})` },
    { k: "announcements", label: `announcements (${announcements.length})` },
  ];

  return (
    <div className="min-h-screen bg-black text-white">
      <Navbar floating={false} />
      <div className="max-w-6xl mx-auto px-6 md:px-10 pt-12 pb-16">
        <p className="text-white/50 text-sm mb-1">admin console</p>
        <h1 className="hero-title text-5xl md:text-6xl font-medium mb-8" data-testid="admin-title">spectral forge</h1>

        <div className="flex flex-wrap gap-2 mb-8">
          {TABS.map((t) => (
            <button
              key={t.k}
              onClick={() => setTab(t.k)}
              data-testid={`admin-tab-${t.k}`}
              className={`text-sm px-5 py-2 rounded-full transition-colors ${tab === t.k ? "bg-white text-black" : "bg-neutral-900/90 text-white/70 hover:text-white"}`}
            >{t.label}</button>
          ))}
        </div>

        {tab === "projects" && (
          <div className="space-y-3" data-testid="admin-projects">
            {projects.map((p) => (
              <div key={p.id} className="bg-neutral-900/60 border border-white/10 rounded-2xl p-5 flex items-start gap-4">
                <div className="flex-1">
                  <h3 className="font-medium">{p.title}</h3>
                  <p className="text-sm text-white/60 mt-1">{p.description}</p>
                  <p className="text-xs text-white/40 mt-2">by {p.owner_name || p.owner_email} · {p.status}</p>
                </div>
                <button onClick={() => delProject(p.id)} data-testid={`admin-delete-project-${p.id}`} className="text-white/40 hover:text-red-400 p-2"><Trash2 size={16} /></button>
              </div>
            ))}
          </div>
        )}

        {tab === "members" && (
          <div className="bg-neutral-900/60 border border-white/10 rounded-2xl overflow-hidden" data-testid="admin-members">
            <table className="w-full text-sm">
              <thead className="bg-white/5 text-left text-xs text-white/60 uppercase tracking-wider">
                <tr><th className="px-5 py-3">name</th><th className="px-5 py-3">email</th><th className="px-5 py-3">role</th><th className="px-5 py-3">provider</th><th className="px-5 py-3">joined</th></tr>
              </thead>
              <tbody>
                {users.map((u) => (
                  <tr key={u.id} className="border-t border-white/5">
                    <td className="px-5 py-3">{u.name || "—"}</td>
                    <td className="px-5 py-3 text-white/70">{u.email}</td>
                    <td className="px-5 py-3"><span className={`text-xs px-2 py-0.5 rounded-full ${u.role === "admin" ? "bg-white text-black" : "bg-white/10"}`}>{u.role}</span></td>
                    <td className="px-5 py-3 text-white/50 text-xs">{u.provider}</td>
                    <td className="px-5 py-3 text-white/50 text-xs">{new Date(u.created_at).toLocaleDateString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        {tab === "contacts" && (
          <div className="space-y-3" data-testid="admin-contacts">
            {contacts.length === 0 ? <p className="text-white/40 text-sm">no contact submissions yet.</p> :
              contacts.map((c) => (
                <div key={c.id} className="bg-neutral-900/60 border border-white/10 rounded-2xl p-5">
                  <div className="flex items-center justify-between mb-2">
                    <div>
                      <p className="font-medium">{c.subject}</p>
                      <p className="text-xs text-white/50">from {c.name} · {c.email}</p>
                    </div>
                    <span className="text-xs text-white/40">{new Date(c.created_at).toLocaleDateString()}</span>
                  </div>
                  <p className="text-sm text-white/70">{c.message}</p>
                </div>
              ))}
          </div>
        )}

        {tab === "announcements" && (
          <div data-testid="admin-announcements">
            <button onClick={() => setShowAnn(true)} data-testid="admin-new-ann-btn" className="bg-white text-black rounded-full px-5 py-3 text-sm mb-6 inline-flex items-center gap-2 hover:bg-neutral-200 transition-colors">
              <Plus size={16} /> post announcement
            </button>
            <div className="space-y-3">
              {announcements.map((a) => (
                <div key={a.id} className="bg-neutral-900/60 border border-white/10 rounded-2xl p-5 flex items-start gap-4">
                  <div className="flex-1">
                    <h3 className="font-medium">{a.title}</h3>
                    <p className="text-sm text-white/60 mt-1">{a.body}</p>
                    <p className="text-xs text-white/40 mt-2">{a.author} · {new Date(a.created_at).toLocaleDateString()}</p>
                  </div>
                  <button onClick={() => delAnn(a.id)} data-testid={`admin-delete-ann-${a.id}`} className="text-white/40 hover:text-red-400 p-2"><Trash2 size={16} /></button>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      {showAnn && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur z-50 flex items-center justify-center p-4">
          <form onSubmit={addAnn} className="bg-neutral-900 border border-white/10 rounded-3xl p-6 max-w-lg w-full space-y-3">
            <div className="flex items-center justify-between"><h2 className="text-xl font-medium">new announcement</h2><button type="button" onClick={() => setShowAnn(false)}><X size={18} /></button></div>
            <input required value={annForm.title} onChange={(e) => setAnnForm({ ...annForm, title: e.target.value })} placeholder="title" data-testid="admin-ann-title" className="w-full bg-black border border-white/10 rounded-xl px-4 py-3 text-sm focus:outline-none focus:border-white/30" />
            <textarea required value={annForm.body} onChange={(e) => setAnnForm({ ...annForm, body: e.target.value })} placeholder="message" rows={5} data-testid="admin-ann-body" className="w-full bg-black border border-white/10 rounded-xl px-4 py-3 text-sm focus:outline-none focus:border-white/30" />
            <button type="submit" data-testid="admin-ann-submit" className="w-full bg-white text-black rounded-full py-3 text-sm hover:bg-neutral-200 transition-colors">post</button>
          </form>
        </div>
      )}
    </div>
  );
}
